package v1beta1

import (
	"context"
	"strings"
	"testing"

	"github.com/openshift/multiarch-tuning-operator/api/common/plugins"
)

func newCPPC(platforms []plugins.NodeAffinityScoringPlatformTerm) *ClusterPodPlacementConfig {
	return &ClusterPodPlacementConfig{
		Spec: ClusterPodPlacementConfigSpec{
			Plugins: &plugins.Plugins{
				NodeAffinityScoring: &plugins.NodeAffinityScoring{
					Platforms: platforms,
				},
			},
		},
	}
}

func TestValidateCreate(t *testing.T) {
	v := &ClusterPodPlacementConfigValidator{}
	ctx := context.Background()

	tests := []struct {
		name      string
		cppc      *ClusterPodPlacementConfig
		expectErr bool
		errSubstr string
	}{
		{
			name: "nil plugins passes",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{},
			},
			expectErr: false,
		},
		{
			name: "unique architectures passes",
			cppc: newCPPC([]plugins.NodeAffinityScoringPlatformTerm{
				{Architecture: "amd64", Weight: 50},
				{Architecture: "arm64", Weight: 50},
			}),
			expectErr: false,
		},
		{
			name: "duplicate architectures rejected",
			cppc: newCPPC([]plugins.NodeAffinityScoringPlatformTerm{
				{Architecture: "amd64", Weight: 50},
				{Architecture: "amd64", Weight: 80},
			}),
			expectErr: true,
			errSubstr: "duplicate architecture",
		},
		{
			name: "single architecture passes",
			cppc: newCPPC([]plugins.NodeAffinityScoringPlatformTerm{
				{Architecture: "arm64", Weight: 100},
			}),
			expectErr: false,
		},
		{
			name: "three entries with one duplicate rejected",
			cppc: newCPPC([]plugins.NodeAffinityScoringPlatformTerm{
				{Architecture: "amd64", Weight: 50},
				{Architecture: "arm64", Weight: 30},
				{Architecture: "amd64", Weight: 20},
			}),
			expectErr: true,
			errSubstr: "duplicate architecture",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := v.ValidateCreate(ctx, tt.cppc)
			if tt.expectErr {
				if err == nil {
					t.Fatalf("expected error but got nil")
				}
				if !strings.Contains(err.Error(), tt.errSubstr) {
					t.Errorf("expected error to contain %q, got %q", tt.errSubstr, err.Error())
				}
			} else {
				if err != nil {
					t.Fatalf("expected no error but got: %v", err)
				}
			}
		})
	}
}

func TestValidateUpdate(t *testing.T) {
	v := &ClusterPodPlacementConfigValidator{}
	ctx := context.Background()

	oldObj := &ClusterPodPlacementConfig{
		Spec: ClusterPodPlacementConfigSpec{},
	}

	tests := []struct {
		name      string
		newObj    *ClusterPodPlacementConfig
		expectErr bool
		errSubstr string
	}{
		{
			name: "update with unique architectures passes",
			newObj: newCPPC([]plugins.NodeAffinityScoringPlatformTerm{
				{Architecture: "amd64", Weight: 50},
				{Architecture: "arm64", Weight: 50},
			}),
			expectErr: false,
		},
		{
			name: "update with duplicate architectures rejected",
			newObj: newCPPC([]plugins.NodeAffinityScoringPlatformTerm{
				{Architecture: "s390x", Weight: 50},
				{Architecture: "s390x", Weight: 80},
			}),
			expectErr: true,
			errSubstr: "duplicate architecture",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := v.ValidateUpdate(ctx, oldObj, tt.newObj)
			if tt.expectErr {
				if err == nil {
					t.Fatalf("expected error but got nil")
				}
				if !strings.Contains(err.Error(), tt.errSubstr) {
					t.Errorf("expected error to contain %q, got %q", tt.errSubstr, err.Error())
				}
			} else {
				if err != nil {
					t.Fatalf("expected no error but got: %v", err)
				}
			}
		})
	}
}
